interface WebSocketHandlers<State> {
  open?(socket: WebSocket, ctx: Context<State>): void;
  message?(socket: WebSocket, event: MessageEvent, ctx: Context<State>): void;
  close?(socket: WebSocket, code: number, reason: string, ctx: Context<State>): void;
  error?(socket: WebSocket, event: Event, ctx: Context<State>): void;
}

interface WebSocketUpgradeOptions extends Deno.UpgradeWebSocketOptions {
  /** Bind the endpoint to its own Deno.serve listener. */
  port?: number;
  /** Optional hostname for the secondary listener. */
  hostname?: string;
}

import { hub } from "./ws-relay.ts";

app.ws("/ws", {
  open(socket, ctx) {
    const userId = ctx.state.userContext?.user?.id;
    if (!userId) {
      socket.close(1008, "Unauthorized");
      return;
    }
    hub.connect(userId, socket);
  },
  message(socket, event) {
    socket.send(`echo: ${event.data}`);
  },
  close(socket, _code, _reason, ctx) {
    const userId = ctx.state.userContext?.user?.id;
    if (userId) hub.disconnect(userId, socket);
  },
  error(_socket, event) {
    const msg = (event as ErrorEvent).message ?? "";
    if (!/connection reset/i.test(msg)) console.error("[WS]", msg);
  },
}, { idleTimeout: 30 });

app.ws("/ws", { /* same handlers */ }, { port: 9000 });

await app.listen({ port: 8000 });
// 🐺 Howl ready
//    Local:    http://localhost:8000/
//    WebSocket: ws://0.0.0.0:9000  ← /ws
